# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import pyotp
import qrcode
from flask import Flask, request, jsonify

app = Flask(__name__)

user_secrets = {}

def generate_totp_secret():
    return pyotp.random_base32()

def generate_qr_code(email, secret):
    uri = pyotp.totp.TOTP(secret).provisioning_uri(email, issuer_name="MFA System")
    img = qrcode.make(uri)
    img.save(f"{email}_qrcode.png")

def verify_totp(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code)

@app.route('/generate_secret', methods=['POST'])
def generate_secret():
    email = request.json['email']
    secret = generate_totp_secret()
    user_secrets[email] = secret
    generate_qr_code(email, secret)
    return jsonify({"secret": secret})

@app.route('/verify_code', methods=['POST'])
def verify_code():
    email = request.json['email']
    code = request.json['code']
    secret = user_secrets.get(email, None)
    if not secret:
        return jsonify({"success": False, "message": "User not found"}), 404
    if verify_totp(secret, code):
        return jsonify({"success": True, "message": "Code verified"})
    else:
        return jsonify({"success": False, "message": "Invalid code"}), 401

if __name__ == '__main__':
    app.run(port=5000)